svg.script:
    
      // Impostazioni base
      const width = 1200;
      const height = 500;
      const columns = 40;
	  const spawnInterval = 5; // in ms
      const minSpeed = 1;        // velocità minima di caduta (pixel/frame)
      const maxSpeed = 2;        // velocità massima di caduta (pixel/frame)
      // Caratteri da usare (puoi personalizzarli)
      const chars = "01A01B01C01D01E01F01G01H01I01J01K01L01M01N01O01P01Q01R01S01T01U01V01W01X01Y01Z01a01b01c01d01e01f01g01h01i01j01k01l01m01n01o01p01q01r01s01t01u01v01w01x01y01z01";
      const svgRoot = document.documentElement;
      
      // Funzione che crea un carattere in caduta in una data posizione orizzontale (x)
      function createFallingChar(x) {
        const textEl = document.createElementNS("http://www.w3.org/2000/svg", "text");
        textEl.setAttribute("x", x);
        textEl.setAttribute("y", "-20");  // partiamo da sopra la finestra
        textEl.setAttribute("fill", "limegreen");
        textEl.setAttribute("font-family", "monospace");
        textEl.setAttribute("font-size", "16");
        // Scegli un carattere casuale
        textEl.textContent = chars[Math.floor(Math.random() * chars.length)];
        
        // Aggiungi l'elemento al DOM SVG
        svgRoot.appendChild(textEl);
        
        // Assegna una velocità casuale
        const speed = Math.random() * (maxSpeed - minSpeed) + minSpeed;
        
        // Funzione ricorsiva per animare la caduta
        function fall() {
          const currentY = parseFloat(textEl.getAttribute("y"));
          if (currentY > height + 50) {
            // Rimuove l'elemento se è uscito dallo schermo
            svgRoot.removeChild(textEl);
            return;
          }
          textEl.setAttribute("y", currentY + speed);
          requestAnimationFrame(fall);
        }
        requestAnimationFrame(fall);
      }
      
      // Calcola lo spazio orizzontale per le colonne
      const columnSpacing = width / columns;
      
      // Genera un nuovo carattere in una colonna casuale ad intervalli regolari
      setInterval(() => {
        const randomColumn = Math.floor(Math.random() * columns);
        createFallingChar(randomColumn * columnSpacing);
      }, spawnInterval);
